import sys
from math import isqrt

def solve():
    MOD = 10**9 + 7
    input_data = sys.stdin.buffer.read().split()
    n = int(input_data[0])
    a = [int(x) for x in input_data[1:n+1]]

    MAX = 10**5 + 1
    phi = list(range(MAX))
    for i in range(2, MAX):
        if phi[i] == i:  # i is prime
            for j in range(i, MAX, i):
                phi[j] -= phi[j] // i

    # Precompute divisors for each value
    # For each a[i], get its divisors
    def get_divisors(x):
        divs = []
        for d in range(1, isqrt(x)+1):
            if x % d == 0:
                divs.append(d)
                if d != x // d:
                    divs.append(x // d)
        return divs

    ans = 0

    for d2 in range(1, n+1):
        # Collect counts: for each d1, count of indices i multiple of d2 where d1|a[i]
        cnt = {}
        for k in range(d2, n+1, d2):
            val = a[k-1]
            for d1 in get_divisors(val):
                cnt[d1] = cnt.get(d1, 0) + 1

        phi_d2 = phi[d2]
        for d1, c in cnt.items():
            ans = (ans + phi[d1] * phi_d2 % MOD * (c * c % MOD)) % MOD

    print(ans)

solve()

